/*
 * bc-products — self-contained custom element bundle. GENERATED by scripts/build.js.
 * Do not hand-edit; edit src/ and run "npm run build".
 *
 * Install: <link rel="stylesheet" href="bc-products.css">
 *          <script src="bc-products.js" defer><\/script>
 *          <bc-products data-store-url="https://store.example.com"
 *                       data-storefront-key="KEY" data-type="new"></bc-products>
 */
(function () {
  'use strict';

  /*
   * bc-products — pure logic + data layer. No DOM globals except `fetch`.
   * DOM/render code stays out of this module — it lives in bc-products.js.
   */
  
  function shuffle(list) {
    const a = list.slice();
    for (let i = a.length - 1; i > 0; i -= 1) {
      const j = Math.floor(Math.random() * (i + 1));
      [a[i], a[j]] = [a[j], a[i]];
    }
    return a;
  }
  
  function dedupeById(list) {
    const seen = new Set();
    return list.filter((p) => (seen.has(p.entityId) ? false : seen.add(p.entityId)));
  }
  
  function hasValidPrice(node) {
    return !!(node && node.defaultImage && node.prices && node.prices.price && node.prices.price.value > 0);
  }
  
  function isOnSale(node) {
    const sp = node?.prices?.salePrice?.value;
    const bp = node?.prices?.basePrice?.value;
    return sp != null && bp != null && sp < bp;
  }
  
  function isSafeHttpUrl(value) {
    if (typeof value !== 'string') return false;
    try {
      const u = new URL(value);
      return u.protocol === 'http:' || u.protocol === 'https:';
    } catch {
      return false;
    }
  }
  
  /* A product path must be store-relative (starts with "/"), which rejects absolute
     URLs ("https://evil.com/…") and non-strings before the href is built. A leading
     "//host" still passes here but is harmless: the fixed `{storeUrl}` prefix
     turns it into a same-origin path, never a new authority. */
  function isStoreRelativePath(path) {
    return typeof path === 'string' && path.startsWith('/');
  }
  
  /* Defense-in-depth: drop any product whose path is not store-relative so the
     fixed-prefix href concatenation can never yield a cross-origin/hostile link. */
  function hasSafePath(node) {
    if (isStoreRelativePath(node?.path)) return true;
    console.warn(`[bc-products] dropping product ${node?.entityId}: non-store-relative path`, node?.path);
    return false;
  }
  
  /* Percent-off badge for an on-sale node, or null when basePrice is unusable
     for a percentage (e.g. 0) — the renderer falls back to plain "Sale" text. */
  function saleBadge(node) {
    const sale = node?.prices?.salePrice?.value;
    const base = node?.prices?.basePrice?.value;
    return sale != null && base > 0 ? Math.round((1 - sale / base) * 100) : null;
  }
  
  /* Node selection set. `description` is opt-in (data-description="true") so the
     default query payload stays lean — see nodeFields(withDescription). */
  const BASE_NODE_FIELDS =
    'entityId name path defaultImage { url(width: 320) } prices { price { value currencyCode } salePrice { value } basePrice { value } }';
  
  function nodeFields(withDescription) {
    return withDescription ? `${BASE_NODE_FIELDS} description` : BASE_NODE_FIELDS;
  }
  
  /* Abort a stalled request so the caller reaches the error/Retry state instead of
     spinning on the skeleton forever. */
  const REQUEST_TIMEOUT_MS = 9000;
  
  async function gql(endpoint, key, query, variables) {
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), REQUEST_TIMEOUT_MS);
    try {
      const res = await fetch(`${endpoint}/graphql`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${key}`, 'Content-Type': 'application/json' },
        body: JSON.stringify({ query, variables }),
        signal: controller.signal,
      });
      if (!res.ok) throw new Error(`GraphQL HTTP ${res.status} for ${endpoint}`);
      const json = await res.json();
      if (json.errors) throw new Error(`GraphQL errors for ${endpoint}: ${JSON.stringify(json.errors)}`);
      return json.data;
    } finally {
      clearTimeout(timer);
    }
  }
  
  async function fetchNew({ storeUrl, key, poolSize, description }) {
    const query = `query($n:Int!){ site { newestProducts(first:$n){ edges { node { ${nodeFields(description)} } } } } }`;
    const data = await gql(storeUrl, key, query, { n: poolSize });
    const nodes = (data?.site?.newestProducts?.edges || []).map((e) => e.node);
    return dedupeById(nodes.filter((n) => hasValidPrice(n) && hasSafePath(n)));
  }
  
  /* searchProducts' categoryEntityIds + searchSubCategories filters expand the whole
     root-plus-descendant union server-side in one call (verified live: 5 roots ->
     408 products), so no separate categoryTree lookup is needed to enumerate ids. */
  async function fetchSale({ storeUrl, key, categoryIds, subcategories, description }) {
    const categoryEntityIds = categoryIds || [];
    if (!categoryEntityIds.length) return [];
    /* Sale fetches one fixed 50-newest page then client-filters to on-sale items —
       one page stays well under the 10000-point complexity limit while still
       filling the display count. */
    const query = `query($ids:[Int!], $sub:Boolean){ site { search { searchProducts(filters:{ categoryEntityIds:$ids, searchSubCategories:$sub }, sort: NEWEST){ products(first:50){ edges { node { ${nodeFields(description)} } } } } } } }`;
    const data = await gql(storeUrl, key, query, { ids: categoryEntityIds, sub: !!subcategories });
    const nodes = (data?.site?.search?.searchProducts?.products?.edges || []).map((e) => e.node);
    return dedupeById(nodes.filter((n) => hasValidPrice(n) && isOnSale(n) && hasSafePath(n)));
  }
  
  const formatters = new Map();
  function getFormatter(currencyCode) {
    let fmt = formatters.get(currencyCode);
    if (!fmt) {
      fmt = new Intl.NumberFormat(undefined, { style: 'currency', currency: currencyCode });
      formatters.set(currencyCode, fmt);
    }
    return fmt;
  }
  
  /* Named HTML entities BigCommerce descriptions commonly emit (typographic +
     Latin-1 accents). Numeric entities are decoded generically in decodeEntity,
     so only names need listing here. */
  const NAMED_ENTITIES = {
    amp: '&', lt: '<', gt: '>', quot: '"', apos: "'", nbsp: ' ', hellip: '…',
    ndash: '–', mdash: '—', lsquo: '‘', rsquo: '’', ldquo: '“', rdquo: '”',
    laquo: '«', raquo: '»', trade: '™', reg: '®', copy: '©', deg: '°', middot: '·',
    bull: '•', times: '×', divide: '÷', frac12: '½', frac14: '¼', frac34: '¾',
    sect: '§', para: '¶', euro: '€', pound: '£', cent: '¢',
    eacute: 'é', Eacute: 'É', egrave: 'è', Egrave: 'È', agrave: 'à', Agrave: 'À',
    acirc: 'â', Acirc: 'Â', ecirc: 'ê', Ecirc: 'Ê', ccedil: 'ç', Ccedil: 'Ç',
    ntilde: 'ñ', Ntilde: 'Ñ', uuml: 'ü', Uuml: 'Ü', ouml: 'ö', Ouml: 'Ö',
    auml: 'ä', Auml: 'Ä', aacute: 'á', Aacute: 'Á', oacute: 'ó', Oacute: 'Ó',
    iacute: 'í', Iacute: 'Í', uacute: 'ú', Uacute: 'Ú', szlig: 'ß',
  };
  
  const ENTITY_RE = /&(#[xX][0-9a-fA-F]+|#\d+|[A-Za-z][A-Za-z0-9]*);/g;
  
  /* Decode one entity token. Numeric decimal (`&#233;`) and hex (`&#x2013;`) are
     resolved via code point; a named token uses NAMED_ENTITIES. Unknown names and
     invalid/out-of-range code points return the ORIGINAL match untouched so a stray
     `&#xZZ;` / `&#9999999999;` / `&notAnEntity;` survives verbatim and never throws. */
  function decodeEntity(match, body) {
    if (body[0] === '#') {
      const hex = body[1] === 'x' || body[1] === 'X';
      const code = parseInt(body.slice(hex ? 2 : 1), hex ? 16 : 10);
      if (code > 0 && code <= 0x10ffff) {
        try {
          return String.fromCodePoint(code);
        } catch {
          return match;
        }
      }
      return match;
    }
    return Object.prototype.hasOwnProperty.call(NAMED_ENTITIES, body) ? NAMED_ENTITIES[body] : match;
  }
  
  /* Reduce product-description HTML to a short plain-text blurb. DOM-free (string
     + regex only, this module has no `document`; a textarea-decode would reintroduce
     an XSS surface via `</textarea>` breakout). Tags are stripped, then entities are
     decoded, then tags are stripped AGAIN — some BC descriptions store their markup
     entity-encoded (`&lt;h2&gt;…`), so decoding reveals real tags the first strip
     could not see. Each tag is replaced by a space, not removed outright, so
     adjacent-tag boundaries (`</h2><p>`, encoded or not) don't fuse the surrounding
     words; the following collapse folds the extra spaces. A rare unpaired literal
     `<`/`>` in prose survives (no closing bracket -> no match); that's inert under
     textContent rendering and never throws. Decoding runs BEFORE the collapse/cut,
     so lengths + word boundaries track real visible text and truncation can never
     split a partial `&...;` sequence. */
  function summarize(html, max = 120) {
    if (typeof html !== 'string' || html === '') return '';
    const text = html
      .replace(/<[^>]*>/g, ' ')
      .replace(ENTITY_RE, decodeEntity)
      .replace(/<[^>]*>/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();
    if (text.length <= max) return text;
    const clipped = text.slice(0, max);
    const lastSpace = clipped.lastIndexOf(' ');
    return `${lastSpace > 0 ? clipped.slice(0, lastSpace) : clipped}…`;
  }
  
  /* Raw card model — no formatting here; the renderer formats price/salePrice/
     basePrice via getFormatter(model.currency) and decides Was/Now/badge markup.
     `blurb` is '' unless the description field was fetched (data-description). */
  function toCardModel(node, storeUrl) {
    const onSale = isOnSale(node);
    const img = node.defaultImage?.url;
    return {
      entityId: node.entityId,
      name: node.name,
      url: `${storeUrl}${node.path}`,
      imageUrl: isSafeHttpUrl(img) ? img : '',
      currency: node.prices.price.currencyCode,
      price: node.prices.price.value,
      salePrice: node.prices?.salePrice?.value ?? null,
      basePrice: node.prices?.basePrice?.value ?? null,
      onSale,
      badge: onSale ? saleBadge(node) : null,
      blurb: summarize(node.description),
    };
  }
  
  const core = { shuffle, dedupeById, hasValidPrice, isOnSale, isSafeHttpUrl, isStoreRelativePath, hasSafePath, saleBadge, gql, fetchNew, fetchSale, getFormatter, summarize, toCardModel };
  
  const ATTR_DEFAULTS = { count: 8, poolSize: 40, columns: 2, subcategories: true, theme: 'light' };
  const TYPES = new Set(['new', 'sale']);
  
  function intAttr(v, dflt, max) {
    const n = parseInt(v, 10);
    if (!Number.isFinite(n) || n <= 0) return dflt;
    return max != null ? Math.min(n, max) : n;
  }
  
  /* Pool feeds newestProducts(first:$n) / caps the sale search page — a merchant
     typo (e.g. data-pool-size="100000") must not be able to exceed the GraphQL
     query complexity limit, so it's clamped well under it regardless of input. */
  const MAX_POOL_SIZE = 50;
  
  function parseConfig(el) {
    const d = el.dataset;
    const storeUrl = (d.storeUrl || '').trim().replace(/\/$/, '');
    const key = (d.storefrontKey || '').trim();
    const type = (d.type || '').trim();
    if (!storeUrl) return { ok: false, error: 'missing required data-store-url' };
    if (!key) return { ok: false, error: 'missing required data-storefront-key' };
    if (!TYPES.has(type)) return { ok: false, error: `invalid data-type "${type}" (expected new|sale)` };
  
    let categoryIds = [];
    if (type === 'sale') {
      categoryIds = (d.categoryId || '').split(',').map((s) => parseInt(s.trim(), 10)).filter((n) => Number.isFinite(n));
      if (categoryIds.length === 0) return { ok: false, error: 'data-type=sale requires data-category-id with at least one numeric id' };
    }
  
    const theme = d.theme === 'dark' ? 'dark' : 'light';
    const title = d.title || (type === 'sale' ? 'On Sale' : 'New Arrivals');
  
    return {
      ok: true,
      config: {
        storeUrl, key, type, categoryIds,
        storeLabel: d.storeLabel || '',
        title,
        viewAll: d.viewAll || '',
        viewAllText: (d.viewAllText || '').trim(),
        count: intAttr(d.count, ATTR_DEFAULTS.count),
        poolSize: intAttr(d.poolSize, ATTR_DEFAULTS.poolSize, MAX_POOL_SIZE),
        columns: intAttr(d.columns, ATTR_DEFAULTS.columns),
        subcategories: d.subcategories !== 'false',
        description: d.description === 'true',
        theme,
        accent: d.accent || '',
        accentDark: d.accentDark || '',
      },
    };
  }
  
  /* Static UI copy — the single place to edit widget text (English). */
  const STRINGS = {
    showing: (n) => `Showing ${n} product${n === 1 ? '' : 's'}`,
    emptyNew: 'No products to show right now — check back soon.',
    emptySale: 'No current deals right now — check back soon.',
    browse: 'Browse the store',
    error: 'Products are temporarily unavailable.',
    retry: 'Retry',
    wasLabel: 'Was ',
    nowLabel: 'Now ',
    saleText: 'Sale',
    viewAll: 'View more',
    viewAllArrow: '→',
  };
  
  function el(tag, className, text) {
    const node = document.createElement(tag);
    if (className) node.className = className;
    if (text != null) node.textContent = text;
    return node;
  }
  
  /* Unique accessible name per instance (kicker + title), e.g. "Boardsports On Sale" —
     without this, two <bc-products> on one page would share an ambiguous landmark name. */
  function labelFor(config) {
    return `${config.storeLabel} ${config.title}`.trim();
  }
  
  function badgeText(model) {
    return model.badge > 0 ? `-${model.badge}%` : STRINGS.saleText;
  }
  
  function buildPrice(model) {
    const price = el('div', 'bc-price');
    if (model.onSale) {
      price.classList.add('bc-price--sale');
      const fmt = core.getFormatter(model.currency);
      price.append(
        el('span', 'bc-sr-only', STRINGS.nowLabel),
        el('span', 'bc-price__now', fmt.format(model.salePrice)),
        el('span', 'bc-sr-only', STRINGS.wasLabel),
        el('s', 'bc-price__was', fmt.format(model.basePrice)),
        el('span', 'bc-badge', badgeText(model)),
      );
    } else {
      price.textContent = core.getFormatter(model.currency).format(model.price);
    }
    return price;
  }
  
  function buildCard(model) {
    const card = el('article', 'bc-card');
  
    const media = el('div', 'bc-card__media');
    const img = document.createElement('img');
    img.className = 'bc-card__img';
    img.alt = '';
    img.loading = 'lazy';
    img.decoding = 'async';
    img.width = 320;
    img.height = 320;
    if (core.isSafeHttpUrl(model.imageUrl)) img.src = model.imageUrl;
    else img.classList.add('bc-card__img--fallback');
    img.addEventListener('error', () => img.classList.add('bc-card__img--fallback'));
    media.appendChild(img);
    card.appendChild(media);
  
    const body = el('div', 'bc-card__body');
    const title = el('h3', 'bc-card__title');
    const link = el('a', 'bc-card__link', model.name);
    link.href = model.url;
    title.appendChild(link);
    body.appendChild(title);
    body.appendChild(buildPrice(model));
    if (model.blurb) body.appendChild(el('p', 'bc-card__desc', model.blurb));
    card.appendChild(body);
  
    return card;
  }
  
  function buildHead(config, label) {
    const head = el('div', 'bc-block__head');
    if (config.storeLabel) head.appendChild(el('p', 'bc-block__kicker', config.storeLabel));
    head.appendChild(el('h2', 'bc-block__title', config.title));
    if (config.viewAll) {
      const text = config.viewAllText || STRINGS.viewAll;
      const viewAll = el('a', 'bc-block__viewall', `${text} ${STRINGS.viewAllArrow}`);
      viewAll.href = config.viewAll;
      viewAll.setAttribute('aria-label', `${text} ${label}`.trim());
      head.appendChild(viewAll);
    }
    return head;
  }
  
  function buildNote(message, action) {
    const note = el('div', 'bc-note');
    note.appendChild(el('p', null, message));
    if (action) note.appendChild(action);
    return note;
  }
  
  function buildStatus(text) {
    const status = el('div', 'bc-sr-only', text);
    status.setAttribute('role', 'status');
    status.setAttribute('aria-live', 'polite');
    return status;
  }
  
  function buildScroll(label) {
    const scroll = el('div', 'bc-scroll');
    scroll.setAttribute('role', 'group');
    scroll.setAttribute('aria-label', label);
    return scroll;
  }
  
  /* Querying scroll/client size forces a synchronous layout, so this reads accurately
     right after the DOM is attached — no need to wait a frame. Both axes are checked:
     the box scrolls vertically on desktop but is a horizontal carousel at <=768px, and
     measuring height alone would leave the mobile carousel unreachable by keyboard. */
  function updateScrollable(scroll) {
    const overflows =
      scroll.scrollHeight > scroll.clientHeight || scroll.scrollWidth > scroll.clientWidth;
    if (overflows) scroll.setAttribute('tabindex', '0');
    else scroll.removeAttribute('tabindex');
  }
  
  /**
   * `<bc-products>` — light-DOM custom element rendering a BigCommerce
   * Storefront GraphQL product block from data-* attributes alone.
   * @see config-attrs.js for the attribute contract, core.js for fetch/filter logic.
   */
  class BcProducts extends HTMLElement {
    connectedCallback() {
      try {
        const result = parseConfig(this);
        if (!result.ok) {
          console.warn('[bc-products]', result.error, this);
          this.renderState('error');
          return;
        }
        const { config } = result;
        this.reserveHeight(config);
        this.dataset.theme = config.theme;
        if (config.accent) this.style.setProperty('--bc-accent', config.accent);
        if (config.accentDark) this.style.setProperty('--bc-accent-dark', config.accentDark);
        this.setAttribute('aria-label', labelFor(config));
        this.dataset.state = 'loading';
        this.load(config);
      } catch (err) {
        console.warn('[bc-products] init failed', err, this);
        this.renderState('error');
      }
    }
  
    /* --bc-rows is intentionally NOT set inline: it must stay at the CSS default in
       BOTH the pre-upgrade :not(:defined) skeleton and the ready state, since CSS
       can't read the element's actual card count before this script runs — an inline
       override here would make the two disagree and reflow the box (the CLS bug this
       fixed height exists to prevent). --bc-cols is safe to set inline because it only
       affects the grid's column count, not the reserved box height. */
    reserveHeight(config) {
      this.style.setProperty('--bc-cols', String(config.columns));
    }
  
    async load(config) {
      try {
        const nodes = config.type === 'sale' ? await core.fetchSale(config) : await core.fetchNew(config);
        // core.fetchNew/fetchSale already apply the junk/on-sale/path filters + dedupe.
        // onSale is a per-block presentation choice, not a data property: core.toCardModel
        // derives it from price data alone, but a New block must show a single price even
        // for a discounted product (fetchNew does not exclude on-sale items), so force it off.
        const chosen = core.shuffle(nodes).slice(0, config.count)
          .map((n) => core.toCardModel(n, config.storeUrl))
          .map((m) => (config.type === 'sale' ? m : { ...m, onSale: false }));
        if (!chosen.length) {
          this.renderState('empty', config);
          return;
        }
        this.renderCards(chosen, config);
      } catch (err) {
        console.warn('[bc-products] fetch failed', config.storeUrl, err);
        this.renderState('error', config);
      }
    }
  
    renderCards(chosen, config) {
      const label = labelFor(config);
      const scroll = buildScroll(label);
  
      const grid = el('div', 'bc-grid');
      chosen.forEach((model) => grid.appendChild(buildCard(model)));
      scroll.appendChild(grid);
  
      const status = buildStatus(STRINGS.showing(chosen.length));
  
      this.dataset.state = 'ready';
      this.replaceChildren(buildHead(config, label), scroll, status);
      updateScrollable(scroll);
    }
  
    /** @param {'empty'|'error'} state @param {object} [config] absent only when parseConfig itself failed */
    renderState(state, config) {
      this.dataset.state = state;
      if (!config) {
        this.replaceChildren(buildNote(STRINGS.error));
        return;
      }
  
      const label = labelFor(config);
      const scroll = buildScroll(label);
      const status = buildStatus('');
  
      if (state === 'empty') {
        let link = null;
        if (config.viewAll) {
          link = el('a', 'bc-note__link', STRINGS.browse);
          link.href = config.viewAll;
        }
        scroll.appendChild(buildNote(config.type === 'sale' ? STRINGS.emptySale : STRINGS.emptyNew, link));
        status.textContent = STRINGS.showing(0);
      } else {
        const retry = el('button', 'bc-note__retry', STRINGS.retry);
        retry.type = 'button';
        retry.addEventListener('click', () => {
          this.dataset.state = 'loading';
          this.load(config);
        });
        scroll.appendChild(buildNote(STRINGS.error, retry));
        status.textContent = STRINGS.error;
      }
  
      this.replaceChildren(buildHead(config, label), scroll, status);
      updateScrollable(scroll);
    }
  }
  
  customElements.define('bc-products', BcProducts);
})();
